// 1. Calculate Period (Previous Month)
const date = new Date();
date.setMonth(date.getMonth() - 1);
const monthNames = ["January", "February", "March", "April", "May", "June",
  "July", "August", "September", "October", "November", "December"
];
const periodText = `Period: ${monthNames[date.getMonth()]} ${date.getFullYear()}`;

// 2. Ledger Mapping
const categoryToLedger = {
  "Omzet AI": "484856606979261540",
  "Omzet SEO": "484856636462073480",
  "Omzet Digital Advertising": "484856624226240149",
  "Omzet Linkbuilding": "484856644527719754",
  "Omzet Website Development": "484856667467417427",
  "Omzet Media Spend": "484856658485314953"
};

// 3. Extract and Clean Data
const categories = ($json.Service_Category || "").split(',').map(s => s.trim()).filter(s => s.length > 0);
const hoursArr = ($json.Hours_Breakdown || "").split(',').map(s => s.trim());
const descriptions = ($json.Description_Breakdown || "").split(',').map(s => s.trim());

// 4. Generate Line Items
const lineItems = categories.map((cat, index) => {
  const rateKey = `${cat} Rate`; 
  const price = parseFloat($json[rateKey]) || 0;

  return {
    "description": `${descriptions[index] || "Work"} - ${cat}\n${periodText}`,
    "amount": parseFloat(hoursArr[index]) || 0, // Moneybird API needs the key to be "amount" for quantity
    "unit": $json.Unit || "hours",
    "price": price,
    "ledger_account_id": categoryToLedger[cat] || "0"
  };
});

return { 
  lineItems,
  count: lineItems.length 
};
